import{_ as e,o as a,c as i,ae as n}from"./chunks/framework.B6gjLfeO.js";const f=JSON.parse('{"title":"Notification & Alerting System","description":"","frontmatter":{"title":"Notification & Alerting System","slug":"notification-alerting-system"},"headers":[],"relativePath":"account-hub/notification-alerting-system.md","filePath":"account-hub/notification-alerting-system.md"}'),o={name:"account-hub/notification-alerting-system.md"};function r(s,t,l,c,h,d){return a(),i("div",null,[...t[0]||(t[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The alerting system lets you set up automatic email alerts on the Branch dashboard to notify you of any data and account settings changes. This will help keep track of any unwanted account changes, reduce the chance of data loss, and increase visibility into postback flows.</p><p>Features include:</p><ul><li>Email alerts based on user role permissions and email address</li><li>Admins enable specific account alerts</li><li>Add recipient emails from the Branch Dashboard</li><li>Unsubscribe directly from the email</li><li>Track the last triggered alert</li></ul><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>Please note that this article explains the <a href="./branch-dashboard-overview.html">legacy Branch experience</a> for receiving notifications and alerts, which is slated for deprecation.</p><p>In the <a href="./new-branch-overview.html">new version of Branch</a>, attribution windows are configured under <strong>Testing &amp; Monitoring</strong> → <a href="./alert-notifications-new.html"><strong>Alert Notifications</strong></a>.</p></div><h3 id="email-alerts" tabindex="-1">Email Alerts <a class="header-anchor" href="#email-alerts" aria-label="Permalink to &quot;Email Alerts&quot;">​</a></h3><p>Branch will notify those on the email list of the following alerts:</p><table tabindex="0"><thead><tr><th>Alert</th><th>Details</th></tr></thead><tbody><tr><td>SAN Authentication Token Expiration</td><td>Notification if a SAN Authentication Token (used to establish a connection between Branch and a SAN) is expired. Users can use this notification to reauthenticate the SAN connection.</td></tr><tr><td>Low Postback Success Rate</td><td>Notification if the success rate of a postback falls below a configurable success threshold over a 24-hour period.</td></tr><tr><td>SAN Partner Change</td><td>Notification if there is a change in the settings of a SAN setting: - Change in authentication - Change in Events Configuration - Change in Attribution Windows</td></tr><tr><td>Branch Global Account Settings Change</td><td>Notification if there is a change in the account configuration of the Branch Dashboard Account Settings; - Account Settings -&gt; Profile - Configuration -&gt; General - Configuration -&gt; Attribution windows</td></tr></tbody></table><h2 id="enabling-alert-notifications" tabindex="-1">Enabling Alert Notifications <a class="header-anchor" href="#enabling-alert-notifications" aria-label="Permalink to &quot;Enabling Alert Notifications&quot;">​</a></h2><p>Enabling the Alert Notification system can be accessed directly through the <strong>Configuration</strong> screen and on the <a href="https://dashboard.branch.io/configuration/alert-notifications" target="_blank" rel="noreferrer"><strong>Alert Notifications</strong> tab</a>. For each alert, you can <strong>configure recipients</strong>, <strong>enable/disable alerts</strong>, <strong>update configuration</strong>, and <strong>subscribe</strong>.</p><h3 id="recipients" tabindex="-1">Recipients <a class="header-anchor" href="#recipients" aria-label="Permalink to &quot;Recipients&quot;">​</a></h3><p>Selecting <strong>Recipients</strong> will allow you to view the full list of users who are receiving emails for a given alert. Here you&#39;ll be able to add/remove recipients by role or by email address. Only admins can add other recipients while individual users can subscribe themselves directly from the subscribe button.</p><h3 id="subscribe" tabindex="-1">Subscribe <a class="header-anchor" href="#subscribe" aria-label="Permalink to &quot;Subscribe&quot;">​</a></h3><p><strong>Subscribe</strong> lets you quickly add yourself to the list of recipients of the alert.</p><h3 id="enable-disable-alert" tabindex="-1">Enable/Disable Alert <a class="header-anchor" href="#enable-disable-alert" aria-label="Permalink to &quot;Enable/Disable Alert&quot;">​</a></h3><p>This action will change the status of the alert to be <strong>ACTIVE</strong> or <strong>DISABLED</strong>. Enabled alerts will allow those in the recipient list to receive emails for the given alert. Note, only admins of the Branch account can enable or disable alerts.</p><h3 id="update-configuration" tabindex="-1">Update Configuration <a class="header-anchor" href="#update-configuration" aria-label="Permalink to &quot;Update Configuration&quot;">​</a></h3><p><strong>Update Configuration</strong> allows you to set the different thresholds for the success rate of <em>Postbacks</em> and <em>Webhooks</em>. Additionally, you can filters for specific ad partners by clicking the <strong>+ Add More Partner(s) Filters</strong> button.</p>',18)])])}const b=e(o,[["render",r]]);export{f as __pageData,b as default};
